export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "02:30。她進門之後沒有開大燈。她開了書桌上的那盞檯燈。燈光是暖黃色的，但房間太暗，暖黃色只夠照亮桌面一小圈。其他地方都是黑的。", background: Background.Chapter_4_Ch4_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她做的第一件事不是脫外套。是拉開斜背包的拉鍊。", background: Background.Chapter_4_Ch4_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的手指摸進內層。小布套還在。她捏了一下。硬的、扁的、圓角的。鏡子還在。她把布套拉出來，打開。小鏡子在掌心裡反了一下檯燈的光。", background: Background.Chapter_4_Ch4_Act2_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "(內心)還在。", background: Background.Chapter_4_Ch4_Act2_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把鏡子放在書桌上。位置靠右，旁邊是悠真失蹤時間線的筆記。她沒有刻意對準什麼位置。但放下之後她發現——它幾乎就在原來的地方。上週一早上它就在這裡。她從這裡出門，去了第七車，然後一切開始。現在它又回到這裡了。像什麼都沒發生過。", background: Background.Chapter_4_Ch4_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但發生過。", background: Background.Chapter_4_Ch4_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看著鏡子。鏡面很小，映出她的一隻眼睛和半邊額頭。額頭上有冷汗乾掉的痕跡。眼睛下面的暗圈比早上更深。", background: Background.Chapter_4_Ch4_Act2_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "(內心)悠真說，妳總是看別人的破綻，偶爾也該看看自己。", background: Background.Chapter_4_Ch4_Act2_S0, portrait: Portrait.AsakuraMio_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "悠真送她這面鏡子的時候，她嫌它幼稚。一個十五歲的男生在學校合作社買的，塑膠外殼，背面印著一隻很醜的貓。她說這什麼。悠真說鏡子啊。她說我知道是鏡子，我問的是為什麼。悠真說，因為妳從來不照鏡子。", background: Background.Chapter_4_Ch4_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有丟掉它。她把它放在書桌上，放在悠真失蹤時間線旁邊。她每天出門前不照鏡子，但她會看一眼它還在不在。像在確認悠真還沒有被完全抹掉。", background: Background.Chapter_4_Ch4_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "現在她不敢把它交出去。她剛看見外殼進了證物袋。血衣進了證物袋。手機被備份。每一樣東西進入流程之後，都變成別人的語言——「金屬外殼狀物」「染血衣物」「數位資料初步保全」。鏡子如果進去，會變成什麼？「塑膠製反射器具」？她不知道。她不想知道。", background: Background.Chapter_4_Ch4_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把鏡子留在書桌上。然後她坐下來。", background: Background.Chapter_4_Ch4_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她從抽屜裡拿出便條紙和舊筆記本。打開手機備忘錄。三樣東西攤在桌上——黃色便條紙、翻到空白頁的筆記本、手機螢幕。她開始寫。", background: Background.Chapter_4_Ch4_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第一件：時間線。她從 21:17 開始寫。匿名訊息送達。21:17 上車。第七車。千田在座位上。千田說的第一句話。千田把外殼塞進她手裡。千田倒下。救護人員到。控制中心。警署。問話。離開。她把每一個時間點寫下來，像在填查核表。不評論。只記。", background: Background.Chapter_4_Ch4_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第二件：座位圖。她翻到筆記本空白頁，畫出第七車的平面。長方形車廂。門在兩端。座位沿兩側排列。千田坐在左側倒數第三個靠窗的位置。她標了血跡起點——不是大腿外側，是肋下往後延伸的方向。她標了監視器位置——車頂，中央偏前。她標了自己站的位置——千田右側。", background: Background.Chapter_4_Ch4_Act2_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "(內心)監視器從上面拍。它看見我站著。它看不見他的手把外殼壓進我掌心。角度不夠低。", background: Background.Chapter_4_Ch4_Act2_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第三件：三個矛盾。她把便條紙撕成三張。一張寫一個。", background: Background.Chapter_4_Ch4_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第一張——畫面缺了一段。千田把外殼塞給她的動作不在中央流裡。她親身經歷了那個動作。他的手指攥住她的手。但中央流裡沒有。紀錄裡寫的是「朝倉澪承認接觸金屬外殼狀物」。沒有交付。沒有被塞。只有接觸。", background: Background.Chapter_4_Ch4_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第二張——外殼不像刀。破邊像刀。三角形、翹起、反光。但裡面有金色接點。整整齊齊。像記憶卡或電子模組的針腳。刀不會有接點。那不是武器。那是什麼東西的殼。從某個設備上被強行撬下來的殼。", background: Background.Chapter_4_Ch4_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第三張——血跡像早已存在。千田外套內側的血不是剛剛才開始流的。邊緣發暗。乾涸。白色膠布的黏性已經失效。不是剛貼的。是撐了很久的。他上車的時候就已經在流血了。", background: Background.Chapter_4_Ch4_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把三張便條紙並排貼在筆記本上方。三個矛盾。三個中央流版本回答不了的問題。三個只有她記得的東西。", background: Background.Chapter_4_Ch4_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她翻到筆記本下一頁。畫了一條直線，把頁面分成左右兩欄。左邊寫「官方看到的」。右邊寫「我記得的」。", background: Background.Chapter_4_Ch4_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "左欄：她手持金屬物站在千田面前。右欄：千田把外殼塞進她手裡。左欄：她手上和袖口沾血。右欄：她按住傷口急救。左欄：千田倒下瞬間。右欄：千田倒下前已臉色灰白。左欄：影像中外殼像刀。右欄：外殼裡有金色接點。", background: Background.Chapter_4_Ch4_Act2_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "(內心)兩欄。同一節車廂。同一個時間。兩個版本。一個被系統記住了。一個只有我記得。", background: Background.Chapter_4_Ch4_Act2_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看著兩欄。左欄是明天所有人會看到的。右欄是她一個人的。", background: Background.Chapter_4_Ch4_Act2_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "(內心)記憶不是證據。但記憶是我現在唯一有的東西。", background: Background.Chapter_4_Ch4_Act2_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第四件：三個目標。她翻到新的一頁。寫下三行。", background: Background.Chapter_4_Ch4_Act2_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "(內心)一，找車載原始影像。二，查銀色外殼是什麼。三，查千田浩介為什麼知道悠真的簡訊是假的。", background: Background.Chapter_4_Ch4_Act2_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看著第三行。千田浩介為什麼知道悠真的簡訊是假的。千田在車上說過——悠真那封「我沒事別擔心」的簡訊不是悠真自己打的。千田怎麼知道？千田是誰？千田為什麼會在第七車？千田為什麼知道她會帶著悠真留下的東西來？", background: Background.Chapter_4_Ch4_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有答案。她把問題寫下來，和另外兩個目標放在一起。三個目標。三個她還不知道怎麼完成的目標。但她把它們寫下來了。寫下來的東西不會消失。不像外殼。不像血衣。不像畫面。", background: Background.Chapter_4_Ch4_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她拿起手機。打開那則匿名訊息——21:17 送達的那則。「想知道朝倉悠真在哪裡，今晚 21:17。灣岸新交通，新木場方向，第七車。帶上悠真留下的那件東西。不要報警。」她試著回覆。打了幾個字。送出。", background: Background.Chapter_4_Ch4_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "送出失敗。帳號不存在。", background: Background.Chapter_4_Ch4_Act2_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "(內心)帳號已經沒了。", background: Background.Chapter_4_Ch4_Act2_S0, portrait: Portrait.AsakuraMio_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看著那行錯誤訊息。帳號不存在。訊息無法送達。那個發訊息給她的人——那個知道她會去第七車、知道她會帶著悠真的東西、知道千田會在那裡的人——已經消失了。像從來沒有存在過。", background: Background.Chapter_4_Ch4_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把手機放下。螢幕暗了。她看著書桌上的筆記本。三個目標。第一個目標的起點——那個發訊息的人——已經斷了。", background: Background.Chapter_4_Ch4_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她往後靠在椅背上。檯燈的光照在她寫滿字的便條紙上。她盯著那些字。然後她的目光移到筆記本最上面——她在時間線最頂端寫了千田的遺言。", background: Background.Chapter_4_Ch4_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "千田說過兩句話。她在車上聽到的。在混亂裡、在血裡、在他倒下之前聽到的。她把它們寫在時間線旁邊。兩句。", background: Background.Chapter_4_Ch4_Act2_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "(內心)「他們會說那是救援。」「不要救東京。」", background: Background.Chapter_4_Ch4_Act2_S0, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看著這兩句話。她把它們並排寫在一起。然後她發現一件奇怪的事。", background: Background.Chapter_4_Ch4_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這兩句話不應該連在一起。", background: Background.Chapter_4_Ch4_Act2_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "(內心)他說「他們會說那是救援」。然後他說「不要救東京」。救援。救。東京。", background: Background.Chapter_4_Ch4_Act2_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第一句裡的「救援」和第二句裡的「救東京」用的是同一個字。救。但方向相反。他們會說那是救援——意思是有人會把某件事包裝成拯救。不要救東京——意思是不要讓那個拯救發生。", background: Background.Chapter_4_Ch4_Act2_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "(內心)東京。他說的不是地名。", background: Background.Chapter_4_Ch4_Act2_S0, portrait: Portrait.AsakuraMio_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她不知道「東京」是什麼。她只知道千田說這兩句話的時候，語氣不像在講地理。像在講一個名字。一個方案。一個他知道的、他恐懼的、他拼了最後一口氣要阻止的東西。", background: Background.Chapter_4_Ch4_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把這個發現寫在便條紙上。沒有結論。只有問題。", background: Background.Chapter_4_Ch4_Act2_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "(內心)「東京」可能不是地名。千田知道它是什麼。我還不知道。", background: Background.Chapter_4_Ch4_Act2_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她寫完這句的時候停了一下。「還不知道」。不是「不知道」。是「還」。她不知道為什麼自己選了這個字。也許是因為她太累了。也許是因為她在跟自己說——你現在不知道，但你會知道。", background: Background.Chapter_4_Ch4_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "04:00。窗外的天還沒有亮。城市在最低的音量上運轉——遠處有垃圾車的聲音，更遠處有什麼在嗶嗶響。她把筆放下。手指僵了。她握筆握了太久。", background: Background.Chapter_4_Ch4_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看著書桌。便條紙。筆記本。座位圖。時間線。三個矛盾。三個目標。兩句遺言。一面小鏡子。", background: Background.Chapter_4_Ch4_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這是她的版本。它不在任何系統裡。它不在任何證物袋裡。它不在任何螢幕上。它只在這裡。在這張桌子上。在她的記憶裡。", background: Background.Chapter_4_Ch4_Act2_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "(內心)他們有畫面。我有版本。畫面不是全部。版本還沒有被寫完。", background: Background.Chapter_4_Ch4_Act2_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有去睡。她知道自己應該睡。但她沒有。她把筆記本翻回座位圖那一頁，又看了一遍。監視器位置。血跡起點。千田的手。她的手。外殼。金色接點。", background: Background.Chapter_4_Ch4_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她反覆看。像查核員在核對最後一版稿件。確認每一個數字都對。確認每一個時間戳都沒有跳。確認她記得的東西和她寫下來的東西是一樣的。", background: Background.Chapter_4_Ch4_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "是一樣的。她記得的，和她寫下來的，是一樣的。", background: Background.Chapter_4_Ch4_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她合上筆記本。把便條紙留在桌上。把鏡子留在旁邊。她沒有收進抽屜。她讓它們留在那裡。留在桌面上。留在檯燈的光圈裡。像在說——這些東西明天還要在。明天她醒來的時候，它們還要在。", background: Background.Chapter_4_Ch4_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她終於站起來。膝蓋還是軟的。她走到床邊，沒有脫外套，直接躺下。太大的外套裹著她，像一個不合身的殼。她閉上眼睛。", background: Background.Chapter_4_Ch4_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有睡著。但她閉著眼睛，讓身體至少水平了。這是她現在能做的最接近休息的事。", background: Background.Chapter_4_Ch4_Act2_S0 },
];
